var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"부르셨나요, 파파?","JPN":"パパ、呼びましたか？","ENG":"Did you call, Papa?","TWN":"你找我嗎，爸爸？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"어라? 방 분위기가 바뀌었네요. 무슨 생각일까요?","JPN":"あれ？　部屋の雰囲気が変わりましたね？　どういうことですか？","ENG":"Oh? The atmosphere of your room's changed. Any reason why?","TWN":"咦？氛圍不太對勁？爸爸在想什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"종신… 계약이요? 그게 뭔가요?","JPN":"終身契約？　なんですかそれは？","ENG":"A lifetime... contract? What's that?","TWN":"終身…契約？那是什麼？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"아… 앞으로도 함께하자는 의미라…","JPN":"あ、これからも一緒にいようって意味か……","ENG":"Oh... it's supposed to mean that we'll be together forever...","TWN":"喔…是要永遠在一起的意思嗎…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"후훗. 저의 언니와 같은 관계가 되고 싶었던 거군요?","JPN":"ふふっ、私の姉さんと同じ関係になりたかったんですね。","ENG":"Haha, so you want to have the same relationship that I have with my sister?","TWN":"嘻嘻，爸爸是想和我成為我跟姊姊那樣的關係嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"이럴 줄 알았으면 언니도 함께 데려오는 거였는데.","JPN":"そうと知っていれば、姉さんも一緒に連れてきたのに。","ENG":"If I knew you were going to propose that, I would've brought her with me.","TWN":"早知道是這樣，我就把姊姊也一起帶來。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"대신 꼭 약속해 줘야 할 것이 있다구요? 앗, 갑자기 무서운 얼굴 하시면…","JPN":"その代わり約束しなければいけないことがあるの？　あ、急に怖い顔になって……","ENG":"But there's something that I must promise? Oh, you're suddenly making a scary face...","TWN":"不過爸爸有個條件？哇，表情突然變得有點可怕…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"에바를 건드리는 건 용납할 수 없다?","JPN":"エヴァに触れることは許せない？","ENG":"I can't harm Eva anymore?","TWN":"不准我再碰耶娃一根寒毛，否則絕不原諒我？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"둘을 지켜보기 위한 종신계약…?","JPN":"二人を見守るための終身契約？","ENG":"The lifetime contract is to watch over the two of us...?","TWN":"這份終身契約是保障我們兩個…？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"히힛, 언니가 괜한 말을 했나 보네요. 저와 언니는 뗄 수 없는 관계라구요.","JPN":"へへっ、姉さんが余計なことを言ったみたいですね。私と姉さんは切り離せない関係なんです。","ENG":"Hehe. Oh, my dear sister said nonsense. You see, she and I are inseparable.","TWN":"嘻嘻，看來姊姊有點多話呢。我和姊姊是無法分開的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그거 아세요? 제가 언니한테 하는 행위는 언니가 전부 허락해 줬기 때문이에요.","JPN":"知ってますか？　私が姉さんに対する行為は姉さんが全部許してくれてるんですよ。","ENG":"Did you know? What I do to her is because she gave me permission to do so.","TWN":"不過爸爸知道嗎？我對姊姊所做的一切，都是經過她同意的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"저에게 뭐든 좋으니까 무언가 느껴지는 것이 생길 때까지 저항하지 않겠다고 했죠.","JPN":"私はかまわないから、何か感じるまで抵抗しないと言ったんです。","ENG":"She said she wouldn't resist until I felt something.","TWN":"她說不管我做什麼都好，直到她有感受為止，她都不會反抗。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그 모든 것을 기꺼이 받아주는 존재가 저희 언니라구요.","JPN":"そのすべてを喜んで受け入れてくれるのが姉さんなんです。","ENG":"That's my sister. Someone who is willing to accept everything about me.","TWN":"能夠欣然接受我的一切，就是我的姊姊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그러니까 제가 언니를 사랑하는 마음은 거짓말이 아니니까… 오해하시면 슬퍼요.","JPN":"だから、姉さんを愛する気持ちは嘘じゃないんです……誤解されると悲しいな。","ENG":"Also, it's not a lie that I love her... So don't be mistaken or I'll be sad.","TWN":"所以我對姊姊的愛不是假的…爸爸誤會我的話，我會很難過的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"갑자기 감정적으로 말하게 되었다구요…? 흠… 그런가…?","JPN":"急に感情的に話すようになったんですって？　うむ……そうかな？","ENG":"I've suddenly become emotional...? Hmm... Have I...?","TWN":"你說我突然變得有點情緒化…？嗯…是嗎…？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"일단 계약할게요. 파파를 보면 언니에게 느껴지는 감정과 비슷한 것 같아요.","JPN":"とりあえず契約します。パパを見ると姉さんに感じる感情と似た感じがするから。","ENG":"I'll sign it for now. Because when I look at you, Papa, I get the same emotions that I get with Eva.","TWN":"好吧，我願意簽字，因為我從爸爸身上有感受到類似姊姊給我的感覺。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"물론 파파 앞에서는 얌전하고 착한 아이로 있는걸 약속할게요. 후훗.","JPN":"もちろん、パパの前ではおとなしくいい子でいることを約束します。ふふっ。","ENG":"And as promised, I'll be a good little girl in front of you. Haha.","TWN":"我答應爸爸，我會在你面前做個乖巧聽話的孩子，呵呵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"그럼… 종신계약이니까 저도 얻는 게 있다는 거잖아요? 뭐가 좋을까?","JPN":"それじゃあ……終身契約だから私も受け取れるものがあるというこですよね？　何がいいかな？","ENG":"Then... this contract means that I get something in return, right? What should I ask for?","TWN":"那…既然是終身契約，我也應該得到些好處吧？會是什麼呢？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DREKA_DOLL_NULL_NULL","text":{"KOREA":"후후후… 일단 차근차근 생각하는 것도 좋겠죠. 저랑… 언니랑… 파파랑 셋이서…","JPN":"ふふふ……とりあえず一つ一つ考えるのもいいですね。私と姉さんと、パパの三人で……","ENG":"Fufufu... I'll keep thinking about it. Just the three of us... You... Eva... and me...","TWN":"呵呵呵…爸爸可以慢慢想。有我…有姊姊…還有爸爸三…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DREKA_DOLL_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};